import { writeOutput } from "./codegen";

const DOCS_URL =
  "https://infisical.com/docs/api-reference/overview/introduction";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Infisical API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:infisical",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const infisicalFirewall = {",
    '  name: "infisical",',
    '  description: "Infisical",',
    "  placeholders: {",
    '    INFISICAL_CLIENT_ID: "00000000-0000-0000-0000-000000000000",',
    '    INFISICAL_CLIENT_SECRET: "InfisicalSecretInfisicalSecret0000000000000",',
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://us.infisical.com",',
    "      auth: {",
    "        headers: {},",
    "      },",
    "      permissions: [],",
    "    },",
    "    {",
    '      base: "https://eu.infisical.com",',
    "      auth: {",
    "        headers: {},",
    "      },",
    "      permissions: [],",
    "    },",
    "    {",
    '      base: "https://app.infisical.com",',
    "      auth: {",
    "        headers: {},",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Infisical firewall config...");
  const ts = generateTypeScript();
  writeOutput("infisical", ts, import.meta.dirname);
}
